import React, { useEffect, useRef } from 'react';
import { Link } from 'react-router-dom';
import { motion, useInView } from 'framer-motion';
import { Dumbbell, Salad, ShoppingBag, Star, ArrowRight, Play, Zap, Target, Users, Award, MessageCircle } from 'lucide-react';

const ADMIN_WHATSAPP = '919999999999';

const fadeUp = {
  initial: { opacity: 0, y: 40 },
  animate: { opacity: 1, y: 0 },
  transition: { duration: 0.6 }
};

const muscleGroups = [
  { name: 'Chest',     icon: '💪', color: 'from-orange-500/20 to-red-500/20', img: 'https://images.unsplash.com/photo-1571019614242-c5c5dee9f50b?w=400&q=80' },
  { name: 'Back',      icon: '🔙', color: 'from-blue-500/20 to-cyan-500/20',   img: 'https://images.unsplash.com/photo-1603287681836-b174ce5074c2?w=400&q=80' },
  { name: 'Shoulders', icon: '🏋️', color: 'from-purple-500/20 to-pink-500/20', img: 'https://images.unsplash.com/photo-1532029837206-abbe2b7620e3?w=400&q=80' },
  { name: 'Arms',      icon: '💪', color: 'from-yellow-500/20 to-orange-500/20',img: 'https://images.unsplash.com/photo-1581009137042-c552e485697a?w=400&q=80' },
  { name: 'Legs',      icon: '🦵', color: 'from-green-500/20 to-teal-500/20',  img: 'https://images.unsplash.com/photo-1434608519344-49d77a699e1d?w=400&q=80' },
  { name: 'Core',      icon: '⚡', color: 'from-red-500/20 to-pink-500/20',    img: 'https://images.unsplash.com/photo-1571019613454-1cb2f99b2d8b?w=400&q=80' },
  { name: 'Cardio',    icon: '🏃', color: 'from-cyan-500/20 to-blue-500/20',   img: 'https://images.unsplash.com/photo-1538805060514-97d9cc17730c?w=400&q=80' },
  { name: 'Full Body', icon: '🔥', color: 'from-orange-500/20 to-yellow-500/20',img:'https://images.unsplash.com/photo-1517836357463-d25dfeac3438?w=400&q=80' },
];

const features = [
  { icon: <Dumbbell className="w-7 h-7 text-orange-500" />, title: 'Expert Workouts', desc: 'Category-wise exercises for every muscle group with video guidance' },
  { icon: <Salad className="w-7 h-7 text-green-400" />,    title: 'Personalized Diet', desc: 'Custom meal plans tailored to your fitness goals by expert trainers' },
  { icon: <ShoppingBag className="w-7 h-7 text-blue-400" />,title: 'Supplement Store', desc: 'Premium quality supplements — protein, creatine, vitamins & more' },
  { icon: <Zap className="w-7 h-7 text-yellow-400" />,      title: 'Auto Reminders', desc: 'Never miss a fee — automatic WhatsApp & website notifications' },
  { icon: <Target className="w-7 h-7 text-purple-400" />,   title: 'Progress Tracking', desc: 'Visual before/after transformations and body progress charts' },
  { icon: <Users className="w-7 h-7 text-pink-400" />,      title: 'Expert Trainers', desc: 'Certified trainers to guide you every step of the fitness journey' },
];

const stats = [
  { value: '500+', label: 'Active Members' },
  { value: '50+', label: 'Expert Programs' },
  { value: '10+', label: 'Years Experience' },
  { value: '200+', label: 'Transformations' },
];

function AnimatedSection({ children, className }) {
  const ref = useRef(null);
  const inView = useInView(ref, { once: true, margin: '-80px' });
  return (
    <motion.div
      ref={ref}
      initial={{ opacity: 0, y: 50 }}
      animate={inView ? { opacity: 1, y: 0 } : {}}
      transition={{ duration: 0.6 }}
      className={className}
    >
      {children}
    </motion.div>
  );
}

export default function HomePage() {
  return (
    <div className="min-h-screen bg-[#0a0a0f]">
      {/* HERO */}
      <section className="relative min-h-screen flex items-center justify-center overflow-hidden bg-grid">
        {/* Background */}
        <div className="absolute inset-0 bg-gradient-to-br from-orange-900/20 via-transparent to-red-900/10" />
        <div className="absolute top-20 left-10 w-64 h-64 bg-orange-500/10 rounded-full blur-3xl" />
        <div className="absolute bottom-20 right-10 w-96 h-96 bg-red-500/10 rounded-full blur-3xl" />

        <div className="relative z-10 text-center px-4 max-w-5xl mx-auto">
          <motion.div {...fadeUp} className="inline-flex items-center gap-2 bg-orange-500/10 border border-orange-500/30 rounded-full px-4 py-2 text-orange-400 text-sm mb-6">
            <Zap size={14} />
            Welcome to FitnessByAjeet — Your Ultimate Gym Experience
          </motion.div>

          <motion.h1
            initial={{ opacity: 0, y: 40 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.7, delay: 0.1 }}
            className="gym-font text-6xl sm:text-7xl md:text-8xl lg:text-9xl text-white mb-4 leading-none"
          >
            TRANSFORM
            <br />
            <span className="gradient-text">YOUR BODY</span>
          </motion.h1>

          <motion.p
            initial={{ opacity: 0, y: 30 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6, delay: 0.3 }}
            className="text-gray-400 text-lg md:text-xl max-w-2xl mx-auto mb-10 leading-relaxed"
          >
            Elite training, nutrition mastery & premium supplements. Join FitnessByAjeet and unleash the athlete within you.
          </motion.p>

          <motion.div
            initial={{ opacity: 0, y: 30 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6, delay: 0.5 }}
            className="flex flex-col sm:flex-row gap-4 justify-center items-center"
          >
            <Link to="/enquiry" className="btn-fire flex items-center gap-2 text-base px-8 py-4">
              Start Your Journey <ArrowRight size={18} />
            </Link>
            <Link to="/exercises" className="flex items-center gap-2 text-white border border-white/20 rounded-lg px-8 py-4 hover:border-orange-500/50 hover:bg-white/5 transition-all text-base">
              <Play size={18} className="text-orange-400" /> Explore Workouts
            </Link>
            <a
              href={`https://wa.me/${ADMIN_WHATSAPP}?text=Hi!%20I'm%20interested%20in%20joining%20FitnessByAjeet`}
              target="_blank" rel="noreferrer"
              className="flex items-center gap-2 text-white bg-green-600 hover:bg-green-500 rounded-lg px-8 py-4 transition-all text-base"
            >
              <MessageCircle size={18} /> WhatsApp Us
            </a>
          </motion.div>
        </div>

        {/* Scroll indicator */}
        <motion.div
          className="absolute bottom-8 left-1/2 transform -translate-x-1/2"
          animate={{ y: [0, 10, 0] }}
          transition={{ repeat: Infinity, duration: 1.5 }}
        >
          <div className="w-6 h-10 border-2 border-white/20 rounded-full flex justify-center pt-2">
            <div className="w-1 h-3 bg-orange-500 rounded-full" />
          </div>
        </motion.div>
      </section>

      {/* STATS */}
      <AnimatedSection className="py-16 border-y border-white/10 bg-white/2">
        <div className="max-w-5xl mx-auto px-6 grid grid-cols-2 md:grid-cols-4 gap-8">
          {stats.map((s, i) => (
            <div key={i} className="text-center">
              <div className="gym-font text-5xl gradient-text mb-1">{s.value}</div>
              <div className="text-gray-400 text-sm">{s.label}</div>
            </div>
          ))}
        </div>
      </AnimatedSection>

      {/* FEATURES */}
      <AnimatedSection className="py-24 px-6">
        <div className="max-w-7xl mx-auto">
          <div className="text-center mb-14">
            <h2 className="gym-font text-5xl text-white mb-3">EVERYTHING YOU <span className="gradient-text">NEED</span></h2>
            <p className="text-gray-400 text-lg">A complete ecosystem for your fitness transformation</p>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {features.map((f, i) => (
              <motion.div
                key={i}
                initial={{ opacity: 0, y: 30 }}
                whileInView={{ opacity: 1, y: 0 }}
                transition={{ delay: i * 0.1, duration: 0.5 }}
                viewport={{ once: true }}
                className="glass rounded-xl p-6 hover:border-orange-500/30 transition-all group"
              >
                <div className="w-12 h-12 rounded-xl bg-white/5 flex items-center justify-center mb-4 group-hover:scale-110 transition-transform">
                  {f.icon}
                </div>
                <h3 className="text-white font-semibold text-lg mb-2">{f.title}</h3>
                <p className="text-gray-400 text-sm leading-relaxed">{f.desc}</p>
              </motion.div>
            ))}
          </div>
        </div>
      </AnimatedSection>

      {/* MUSCLE CATEGORIES */}
      <AnimatedSection className="py-24 px-6 bg-white/2">
        <div className="max-w-7xl mx-auto">
          <div className="text-center mb-14">
            <h2 className="gym-font text-5xl text-white mb-3">TRAIN BY <span className="gradient-text">MUSCLE GROUP</span></h2>
            <p className="text-gray-400 text-lg">Targeted exercises for every major muscle group</p>
          </div>
          <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 gap-4">
            {muscleGroups.map((m, i) => (
              <motion.div
                key={i}
                initial={{ opacity: 0, scale: 0.9 }}
                whileInView={{ opacity: 1, scale: 1 }}
                transition={{ delay: i * 0.08, duration: 0.4 }}
                viewport={{ once: true }}
                whileHover={{ scale: 1.05 }}
              >
                <Link
                  to={`/exercises?muscle=${m.name.toLowerCase().replace(' ', '-')}`}
                  className={`relative block rounded-xl overflow-hidden h-40 bg-gradient-to-br ${m.color} border border-white/10 group cursor-pointer`}
                >
                  <img src={m.img} alt={m.name} className="absolute inset-0 w-full h-full object-cover opacity-40 group-hover:opacity-60 transition-opacity" />
                  <div className="absolute inset-0 bg-gradient-to-t from-black/70 to-transparent" />
                  <div className="absolute bottom-0 left-0 right-0 p-3 text-center">
                    <div className="text-2xl mb-1">{m.icon}</div>
                    <div className="text-white font-bold text-sm">{m.name}</div>
                  </div>
                </Link>
              </motion.div>
            ))}
          </div>
          <div className="text-center mt-8">
            <Link to="/exercises" className="btn-fire inline-flex items-center gap-2">View All Exercises <ArrowRight size={16} /></Link>
          </div>
        </div>
      </AnimatedSection>

      {/* CTA BANNER */}
      <AnimatedSection className="py-24 px-6">
        <div className="max-w-4xl mx-auto">
          <div className="relative rounded-2xl overflow-hidden bg-gradient-to-br from-orange-500/20 to-red-500/10 border border-orange-500/30 p-10 md:p-16 text-center">
            <div className="absolute top-0 right-0 w-64 h-64 bg-orange-500/10 rounded-full blur-3xl" />
            <Award size={48} className="text-orange-400 mx-auto mb-4" />
            <h2 className="gym-font text-5xl text-white mb-4">READY TO <span className="gradient-text">CRUSH IT?</span></h2>
            <p className="text-gray-300 text-lg mb-8">Join hundreds of members who transformed their lives with FitnessByAjeet</p>
            <div className="flex flex-col sm:flex-row gap-4 justify-center">
              <Link to="/enquiry" className="btn-fire text-lg px-10 py-4">Join Now</Link>
              <a
                href={`https://wa.me/${ADMIN_WHATSAPP}?text=I%20want%20to%20join%20FitnessByAjeet!`}
                target="_blank" rel="noreferrer"
                className="flex items-center justify-center gap-2 text-white bg-green-600 hover:bg-green-500 rounded-lg px-10 py-4 text-lg transition-all"
              >
                <MessageCircle size={20} /> WhatsApp
              </a>
            </div>
          </div>
        </div>
      </AnimatedSection>
    </div>
  );
}
